const NotaryDashboard  = ({ data, confirm, label, item }) => {

	// const { modalID } = data;

	const [obs, set_obs] = useState(1);
	const [init, setInit] = useState(false);


	useEffect(() => {
		if(!init){
			if(!getStore("notary_list")){
				fetchListNotary("notary_list", updObs);
			}
			setInit(true);
		}
	});



	const updObs =  (v) => {
		set_obs(gen16CodeId());
    }
	
	const confirmCalendar =  (v) => {
		set_obs(gen16CodeId());
    }
	
	const openCalendar = () => {
        let modal_data = {};
        modal_data["zIndex"] = 950;
        modal_data["height"] = "80vh";
        // data['observeResize']=true;
        modal_data["props"] = { minHeight: "1vh", overlay: true };
        modal_data["content"] = 
			<CalendarModalPicker 
				onConfirm={confirmCalendar} 
				init={getStore("date_range_comps")?.initDate}
				appoitmentType={true}
				//last={getStore("date_range_comps")?.lastDate}
				//isRange={true}
			/>
        
        OpenModal(modal_data);
	}
   

	

    return (
       
		<div >
			<div className="listFlx  ">
				<p className="nav_title_header header_mobile" >
					<NavLink className=" jaqJnq bVyKiY"  to={"/"}>
						{"Stephanie Solution Group"}
					</NavLink>
				</p>
			</div>

			<div className="code_prod_header">
				<div className="fxOkFE"  >
				{"Servicios de Notaria y Aplicaciones de Inmigracion"}
				</div>
			</div>


			

		
			<div className="listFlx spaceAround flxWrp w_100prc" >
				
				{
					getStore("notary_list") && getStore("notary_list").map((dataTab, inD1)=>{
						return (
								<PlanTabOffers 
									key={dataTab.title +"_"+ inD1}
									dataTab={dataTab}
								/>
						)
					})
				}
				

			
			</div>

			
		

		</div>
    )   
}

export default NotaryDashboard;




