import { fetchGet, getUrlServerSide, updStore, getStore, gen16CodeId } from "../../../stores/Utils";

export const fetchListNotary = async (coll, cb) => {
    let lastTimeCallModal = getStore("lastTimeCall_fetchListNotary") || 0;
    if(Date.now() > lastTimeCallModal){
        updStore("lastTimeCall_fetchListNotary", Date.now()+320);
        let data = await  fetchGet(getUrlServerSide() + "/getStatic?fileName=notary_services_list_v2.json&k="+gen16CodeId())
        updStore(coll,data);
        if(typeof cb === "function"){
            cb();
        }
    }
}

export const fetchNotaryItem = async (qry,coll, cb, eq) => {
    let lastTimeCallModal = getStore("lastTimeCall_fetchNotaryItem") || 0;
    if(Date.now() > lastTimeCallModal){
        updStore("lastTimeCall_fetchNotaryItem", Date.now()+320);
        let data = await  fetchGet(getUrlServerSide() + "/getStatic?fileName="+qry+"_v2.json&k="+eq)
        updStore(coll,data);
        if(typeof cb === "function"){
            cb(data);
        }
    }
}